ORDER BY salario DESC LIMIT 1 OFFSET 1;

WITH ventas_top AS (
  SELECT vendedor_id, SUM(monto) AS total
  FROM ventas
  GROUP BY vendedor_id
)
SELECT * FROM ventas_top WHERE total > 10000;

SELECT nombre, dept, salario,
  AVG(salario) OVER (PARTITION BY dept) AS avg_dept
FROM empleados;

SELECT fecha, ventas,
  SUM(ventas) OVER (
    ORDER BY fecha
    ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW
  ) AS acumulado
FROM ventas_diarias;

SELECT * FROM (
  SELECT categoria, producto, ventas,
    ROW_NUMBER() OVER(
      PARTITION BY categoria
      ORDER BY ventas DESC
    ) AS rn
  FROM productos
) t WHERE rn <= 3;

